class Solution {
    public int maxSubstrings(String word) {
        int n = word.length();
        int[] first = new int[26];
        int[] last  = new int[26];
        java.util.Arrays.fill(first, -1);
        for (int i = 0; i < n; ++i) {
            int c = word.charAt(i) - 'a';
            if (first[c] == -1) first[c] = i;
            last[c] = i;
        }

        java.util.List<int[]> segs = new java.util.ArrayList<>();
        for (int c = 0; c < 26; ++c) {
            if (first[c] != -1 && last[c] - first[c] + 1 >= 4) {
                segs.add(new int[]{first[c], last[c]});
            }
        }

        segs.sort((a, b) -> Integer.compare(a[1], b[1]));

        int res = 0;
        int prevEnd = -1;
        for (int[] seg : segs) {
            if (seg[0] > prevEnd) {
                ++res;
                prevEnd = seg[1];
            }
        }
        return res;
    }
}
